option.value:
:root {
  font-family: "Manrope", "Segoe UI", sans-serif;
  line-height: 1.5;
  color: #1f2937;
  background-color: #f8fafc;
}

* {
  box-sizing: border-box;
}

body {
  margin: 0;
  min-height: 100vh;
  background:
    radial-gradient(circle at 90% 10%, rgba(14, 165, 233, 0.15), transparent 40%),
    radial-gradient(circle at 10% 90%, rgba(16, 185, 129, 0.15), transparent 35%),
    #f8fafc;
}

#app {
  min-height: 100vh;
}

.page {
  min-height: 100vh;
  display: grid;
  place-items: center;
  padding: 1rem;
}

.card {
  width: min(640px, 100%);
  background: #ffffff;
  border: 1px solid #e2e8f0;
  border-radius: 16px;
  padding: 1.5rem;
  box-shadow: 0 12px 24px rgba(15, 23, 42, 0.08);
}

h1 {
  margin: 0 0 1rem;
  font-size: 2rem;
  letter-spacing: -0.02em;
}

h2 {
  margin: 0;
  font-size: 1.2rem;
  letter-spacing: -0.01em;
}

.section {
  margin-top: 1.25rem;
}

.error {
  color: #b91c1c;
}

.info {
  color: #0f766e;
}

.note {
  margin: 0.5rem 0 0;
  color: #475569;
}

.calc-form {
  display: grid;
  gap: 0.8rem;
  margin-top: 0.8rem;
}

.field {
  display: grid;
  gap: 0.4rem;
  font-weight: 600;
}

.field span {
  font-size: 0.92rem;
}

.field input,
.field select {
  width: 100%;
  padding: 0.7rem 0.75rem;
  border: 1px solid #cbd5e1;
  border-radius: 10px;
  background: #f8fafc;
  color: #1f2937;
  font-size: 0.98rem;
}

.field input:focus,
.field select:focus {
  outline: 2px solid #38bdf8;
  border-color: #38bdf8;
}

.button {
  border: none;
  border-radius: 10px;
  padding: 0.8rem 1rem;
  font-size: 1rem;
  font-weight: 700;
  color: #ffffff;
  background: linear-gradient(120deg, #0ea5e9, #0284c7);
  cursor: pointer;
}

.button:hover {
  filter: brightness(1.04);
}

.button-danger {
  background: linear-gradient(120deg, #ef4444, #dc2626);
}

.button-primary {
  background: linear-gradient(120deg, #0ea5e9, #0284c7);
}

.button-secondary {
  background: #e2e8f0;
  color: #1f2937;
}

.button-small {
  padding: 0.45rem 0.65rem;
  font-size: 0.85rem;
}

.subject-list {
  list-style: none;
  padding: 0;
  margin: 0;
  display: grid;
  gap: 0.75rem;
}

.subject-item {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 0.75rem;
  background: #f8fafc;
  border: 1px solid #e2e8f0;
  border-radius: 12px;
  padding: 0.75rem 1rem;
}

.subject-item div {
  display: grid;
}

.subject-item small {
  color: #64748b;
}

.subject-actions {
  display: flex;
  align-items: center;
  gap: 0.6rem;
}

@media (max-width: 540px) {
  h1 {
    font-size: 1.65rem;
  }

  h2 {
    font-size: 1.1rem;
  }

  .subject-item {
    align-items: flex-start;
    flex-direction: column;
  }

  .subject-actions {
    width: 100%;
    justify-content: space-between;
  }
}

/* Modal styles */
.modal-overlay {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: rgba(0, 0, 0, 0.5);
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 1rem;
  z-index: 1000;
}

.modal {
  background: #ffffff;
  border-radius: 12px;
  box-shadow: 0 20px 25px rgba(0, 0, 0, 0.15);
  max-width: 500px;
  width: 100%;
  max-height: 90vh;
  overflow-y: auto;
  animation: slideIn 0.3s ease-out;
}

@keyframes slideIn {
  from {
    opacity: 0;
    transform: translateY(-20px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.modal-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 1.5rem;
  border-bottom: 1px solid #e2e8f0;
}

.modal-header h2 {
  margin: 0;
  font-size: 1.3rem;
}

.modal-close {
  background: none;
  border: none;
  font-size: 1.5rem;
  cursor: pointer;
  color: #64748b;
  padding: 0;
  width: 32px;
  height: 32px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 6px;
  transition: all 0.2s;
}

.modal-close:hover {
  background: #f1f5f9;
  color: #1f2937;
}

.modal-body {
  padding: 1.5rem;
}

.modal-actions {
  display: flex;
  gap: 0.8rem;
  justify-content: flex-end;
  margin-top: 1.5rem;
  padding-top: 1.5rem;
  border-top: 1px solid #e2e8f0;
}

.modal-actions .button {
  flex: 1;
}

@media (max-width: 540px) {
  .modal {
    max-width: 90vw;
  }

  .modal-actions {
    flex-direction: column;
  }

  .modal-actions .button {
    width: 100%;
  }
}

